export const ESSAY_PASSAGES = PASSAGES;

const TOPIC_INDEX = PASSAGES.reduce((acc, p) => {
  acc[p.topic] = p;
  return acc;
}, {});

export function getEssayPassagesForTopic(topic) {
  if (!topic) return null;
  return TOPIC_INDEX[topic] || null;
}
